#include <bits/stdc++.h>
using namespace std;
int main(){
    long long n; cin >> n;
    long long lo = 0, hi = n;
    while (lo < hi) {
        long long mid = lo + (hi - lo + 1) / 2;
        if (mid * mid <= n) lo = mid;
        else hi = mid - 1;
    }
    cout << lo << "\n";
}
